/** Parse rate string to decimal (e.g. '4%' → 0.04, '4.4¢/kg' → null for unit-based) */
function parseRate(rateStr: string): number | null {
  if (!rateStr || rateStr === 'Free' || rateStr.toLowerCase().startsWith('free')) return 0;
  const pct = rateStr.match(/([0-9.]+)%/);
  if (pct) return parseFloat(pct[1]) / 100;
  return null; // specific duty (¢/kg, etc.)
}

/**
 * Look up TRQ entries for a given HTS code.
 * Matches by exact code or prefix (10-digit → 8 → 6 → 4).
 */
export function lookupTRQ(htsCode: string): TRQLookupResult {
  const clean = htsCode.replace(/[.\s]/g, '');
  // Try longest match first
  for (const len of [10, 8, 6, 4]) {
    const prefix = clean.substring(0, len);
    const entry = US_TRQ_ENTRIES.find(e => {
      const ec = e.hts_code.replace(/[.\s]/g, '');
      return ec === prefix || ec.startsWith(prefix);
    });
    if (entry) {
      const inQuota = parseRate(entry.general_rate);
      const overQuota = parseRate(entry.other_rate);
      const hasTRQ = inQuota !== null && overQuota !== null && overQuota > (inQuota ?? 0);
      return {
        found: true,
        entry,
        hasTRQ,
        inQuotaRate: inQuota ?? undefined,
        overQuotaRate: overQuota ?? undefined,
        note: hasTRQ
          ? `TRQ: in-quota ${entry.general_rate} / over-quota ${entry.other_rate}`
          : `Rate: ${entry.general_rate}`,
      };
    }
  }
  return { found: false, hasTRQ: false, note: 'No TRQ entry found' };
}